# Generated by ollama (deepseek-coder:6.7b-instruct)
# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
    agent any  // Run this pipeline on any available node
    
    stages {
        stage('Build') {
            steps {
                sh 'mvn clean install'  // Use Maven for building and testing the application
            }
        }
        
        stage('Deploy to Production') {
            steps {
                sh 'scp target/*.jar user@production-server:/path/to/deployment'  // Copy built jar file to production server
                sshagent(['jenkins_ssh']) {   // Assume you have a private key for SSH access
                    sh 'ssh user@production-server "cd /path/to/deployment; java -jar *.jar"'  // Deploy the application on production server
                }
            }
        }
    }
}